// // This module implements an ALU with operations selected by 'op'. When 'op' is '00', it subtracts B from A; when 'op' is '01', it adds A and B; when 'op' is '10', it performs a bitwise OR between A and B; and when 'op' is '11', it performs a bitwise AND.
module top_module(output reg [15:0] Z, input [1:0] op, input [15:0] A, B, C);always @(*) begin
        case (op)
            2'b00: Z = A + B;
            2'b01: Z = A - B;
            2'b10: Z = A & B;
            2'b11: Z = A | B;
        endcase
    end

endmodule
